use crate::harness::{self, format_count, gen_floats, BenchResult};
use base::{Algorithm, BaseConfig};

// ---------------------------------------------------------------------------
// Vector Addition Benchmark
//
// Compares Rust, Burn (NdArray), and Base (Cranelift JIT) for vec_add + sum.
//
// Algorithm CLIF IR is generated by Lean at build time (see lean/ directory).
// ---------------------------------------------------------------------------

type B = burn::backend::NdArray<f32>;

const VECOPS_ALGORITHM: &[u8] = include_bytes!(concat!(env!("OUT_DIR"), "/vecops_algorithm.bin"));

fn load_algorithm() -> (BaseConfig, Algorithm) {
    bincode::deserialize(VECOPS_ALGORITHM).expect("Failed to deserialize vecops algorithm")
}

fn rust_vec_add(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    for i in 0..a.len() {
        sum += (a[i] + b[i]) as f64;
    }
    sum
}

fn burn_vec_add(a: &[f32], b: &[f32]) -> f64 {
    use burn::tensor::{Tensor, TensorData};
    let n = a.len();
    let device = Default::default();
    let a_t = Tensor::<B, 1>::from_data(TensorData::new(a.to_vec(), [n]), &device);
    let b_t = Tensor::<B, 1>::from_data(TensorData::new(b.to_vec(), [n]), &device);
    let c_t = a_t + b_t;
    c_t.sum().into_scalar() as f64
}

/// Build payload: [A floats...][B floats...]
/// n is derived from data_len / 8
fn build_payload(a: &[f32], b: &[f32]) -> Vec<u8> {
    let mut payload = Vec::with_capacity((a.len() + b.len()) * 4);
    for &v in a {
        payload.extend_from_slice(&v.to_le_bytes());
    }
    for &v in b {
        payload.extend_from_slice(&v.to_le_bytes());
    }
    payload
}

fn close_enough(a: f64, b: f64) -> bool {
    if a.is_nan() || b.is_nan() {
        return false;
    }
    let diff = (a - b).abs();
    let mag = a.abs().max(b.abs()).max(1.0);
    diff / mag < 0.01
}

pub fn run(iterations: usize) -> Vec<BenchResult> {
    let sizes: &[usize] = &[1_000_000, 10_000_000, 50_000_000];
    let mut results = Vec::new();

    // JIT compile once
    let (config, alg) = load_algorithm();
    let mut base_instance = base::Base::new(config).expect("Base::new failed");

    for &n in sizes {
        let a = gen_floats(n, 42);
        let b = gen_floats(n, 123);

        let payload = build_payload(&a, &b);

        // Raw Rust
        let rust_ms = harness::median_of(iterations, || {
            let start = std::time::Instant::now();
            std::hint::black_box(rust_vec_add(&a, &b));
            start.elapsed().as_secs_f64() * 1000.0
        });

        // Burn (NdArray CPU)
        let burn_ms = {
            use burn::tensor::{Tensor, TensorData};
            let device = Default::default();
            let a_t = Tensor::<B, 1>::from_data(TensorData::new(a.to_vec(), [n]), &device);
            let b_t = Tensor::<B, 1>::from_data(TensorData::new(b.to_vec(), [n]), &device);
            harness::median_of(iterations, || {
                let start = std::time::Instant::now();
                let c_t = a_t.clone() + b_t.clone();
                std::hint::black_box(c_t.sum().into_scalar());
                start.elapsed().as_secs_f64() * 1000.0
            })
        };

        // Base (Cranelift JIT) — execute with payload, read result from out buffer
        let mut out_buf = [0u8; 8];

        // Warmup
        let _ = base_instance.execute_into(&alg, &payload, &mut out_buf);

        let base_ms = harness::median_of(iterations, || {
            let start = std::time::Instant::now();
            let _ = base_instance.execute_into(&alg, &payload, &mut out_buf);
            start.elapsed().as_secs_f64() * 1000.0
        });

        let base_result = f64::from_le_bytes(out_buf);
        let rust_check = rust_vec_add(&a, &b);
        let burn_check = burn_vec_add(&a, &b);
        let verified =
            Some(close_enough(rust_check, burn_check) && close_enough(rust_check, base_result));

        results.push(BenchResult {
            name: format!("VecAdd ({})", format_count(n)),
            col_a_ms: Some(rust_ms),
            col_b_ms: Some(burn_ms),
            base_ms,
            verified,
        });
    }

    results
}
